create table if not exists public.finance_bank_accounts(id uuid primary key default gen_random_uuid(),name text not null,institution text not null default '',account_type text not null default 'checking',last_four text not null default '',opening_balance_cents integer not null default 0,active boolean not null default true,created_by uuid not null references auth.users(id),created_at timestamptz not null default now(),updated_at timestamptz not null default now());create table if not exists public.finance_balance_snapshots(id uuid primary key default gen_random_uuid(),account_id uuid not null references public.finance_bank_accounts(id) on delete cascade,balance_date date not null,current_balance_cents integer not null,available_balance_cents integer,notes text not null default '',created_by uuid not null references auth.users(id),created_at timestamptz not null default now(),unique(account_id,balance_date));alter table public.finance_bank_accounts enable row level security;alter table public.finance_balance_snapshots enable row level security;create policy "Executives manage bank accounts" on public.finance_bank_accounts for all to authenticated using(exists(select 1 from public.organization_members m where m.user_id=auth.uid() and m.active and m.role in('executive','admin'))) with check(exists(select 1 from public.organization_members m where m.user_id=auth.uid() and m.active and m.role in('executive','admin')));create policy "Executives manage balance snapshots" on public.finance_balance_snapshots for all to authenticated using(exists(select 1 from public.organization_members m where m.user_id=auth.uid() and m.active and m.role in('executive','admin'))) with check(exists(select 1 from public.organization_members m where m.user_id=auth.uid() and m.active and m.role in('executive','admin')));grant select,insert,update,delete on public.finance_bank_accounts,public.finance_balance_snapshots to authenticated;
